CREATE SCHEMA MARKETING;
GO
CREATE TABLE MARKETING.MARKETING_CAMPAIGNS(
 CAMPAIGN_ID INT PRIMARY KEY, CAMPAIGN_NAME NVARCHAR(200), CAMPAIGN_CODE NVARCHAR(50),
 CHANNEL NVARCHAR(50), SUB_CHANNEL NVARCHAR(50), START_DATE DATE, END_DATE DATE,
 TOTAL_SPEND DECIMAL(15,2), CUSTOMERS_ACQUIRED INT, STATUS NVARCHAR(20),
 CREATED_DATE DATETIME2, LAST_UPDATE_DATE DATETIME2);
GO
